#include<bits/stdc++.h>using namespace std;int n,a[110]; struct node{	int x,y; };int main(){    int t;	cin>>t;	while(t--){		int f=0;		memset(a,0,sizeof(a));		cin>>n; 		for(int i=1;i<=n;i++)cin>>a[i];		for(int i=1;i<n;i++){			if(a[i]!=a[i+1]){				f=1;				break;			}		} 		if(f==0){			cout<<0<<"\n";			continue;		}		f=0;		for(int i=1;i<=n;i++){			if(a[i]==1){				f=1;				break;			}		} 		if(f==1){			cout<<-1<<"\n";			continue;		}		queue<node> q; 		while(true){			bool flag=false;			for(int i=1;i<=n;i++){				for(int j=1;j<=n;j++){					if(a[i]<a[j]){						q.push({j,i});						a[j]=(a[j]+a[i]-1)/a[i];						flag=true;						} 				}			}			if(flag==false){				break;			}		} 		cout<<q.size()<<"\n"; 		while(q.size()>0){			cout<<q.front().x<<" "<<q.front().y<<"\n";			q.pop();		}	}     return 0;}